import "./EmployeeHoursTable.css";

interface EmployeeHoursProps {
 data: any[];
 loading: boolean;
}

export default function EmployeeHoursTable({ data, loading }: EmployeeHoursProps) {
 if (loading) {
 return <div className="loading-state">Loading dashboard data...</div>;
 }

 if (data.length === 0) {
 return (
 <div className="empty-state">
 No approved work logs found.
 </div>
 );
 }

 return (
 <div className="hours-table-container">
 <table className="hours-table">
 <thead>
 <tr>
 <th>Employee</th>
 <th>Total Hours</th>
 </tr>
 </thead>
 <tbody>
 {data.map((item, index) => (
 <tr key={index}>
 <td>{item.groupby_fields?.[0]?.display_value || "Unknown"}</td>
 <td className="hours-cell">
 {parseFloat(item.stats?.sum?.hours_worked || "0").toFixed(1)}
 </td>
 </tr>
 ))}
 </tbody>
 </table>
 </div>
 );
}
",".hours-table-container {
 background: rgb(var(--now-container--background-color, 255, 255, 255));
 border-radius: 8px;
 box-shadow: 0 1px 4px rgba(0, 0, 0, 0.08);
 overflow: hidden;
}

.hours-table {
 width: 100%;
 border-collapse: collapse;
}

.hours-table thead {
 background: rgb(var(--now-container--background-color--secondary, 245, 245, 245));
}

.hours-table th {
 padding: 12px 16px;
 text-align: left;
 font-weight: 600;
 font-size: 13px;
 color: rgb(var(--now-color--text--secondary, 100, 100, 100));
 text-transform: uppercase;
 letter-spacing: 0.5px;
}

.hours-table td {
 padding: 12px 16px;
 border-bottom: 1px solid rgb(var(--now-container--border-color, 230, 230, 230));
 font-size: 14px;
 color: rgb(var(--now-color--text--primary, 41, 41, 41));
}

.hours-table tbody tr:hover {
 background: rgb(var(--now-container--background-color--hover, 248, 248, 248));
}

.hours-cell {
 font-weight: 600;
 color: rgb(var(--now-actionable--primary--background-color, 0, 128, 163));
}

.loading-state,
.empty-state {
 text-align: center;
 padding: 40px 20px;
 color: rgb(var(--now-color--text--secondary, 100, 100, 100));
 font-size: 14px;
}
",".dashboard {
 max-width: 900px;
 margin: 0 auto;
 padding: 24px;
 font-family: var(--now-font-family, "Lato", "Helvetica Neue", sans-serif);
}

.dashboard-header {
 margin-bottom: 24px;
}

.dashboard-title {
 font-size: 24px;
 font-weight: 700;
 color: rgb(var(--now-color--text--primary, 41, 41, 41));
 margin: 0 0 4px 0;
}

.dashboard-subtitle {
 font-size: 14px;
 color: rgb(var(--now-color--text--secondary, 100, 100, 100));
 margin: 0;
}

.dashboard-summary {
 display: flex;
 gap: 16px;
 margin-bottom: 24px;
}

.summary-card {
 flex: 1;
 background: rgb(var(--now-container--background-color, 255, 255, 255));
 border-radius: 8px;
 padding: 20px;
 box-shadow: 0 1px 4px rgba(0, 0, 0, 0.08);
 display: flex;
 flex-direction: column;
 gap: 8px;
}

.summary-label {
 font-size: 13px;
 color: rgb(var(--now-color--text--secondary, 100, 100, 100));
 text-transform: uppercase;
 letter-spacing: 0.5px;
}

.summary-value {
 font-size: 32px;
 font-weight: 700;
 color: rgb(var(--now-actionable--primary--background-color, 0, 128, 163));
}
